@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationService
@inject PersistentComponentState ApplicationState
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;
    private DateTime _latestTimestamp = DateTime.MinValue;

    protected override void OnInitialized()
    {
        // During SSR this persists data into the page so the interactive
        // runtime can pick it up without re-fetching.
        _persistSub = ApplicationState.RegisterOnPersisting(() =>
        {
            ApplicationState.PersistAsJson("notifications", _notifications);
            return Task.CompletedTask;
        });

        if (ApplicationState.TryTakeFromJson<List<Notification>>(
                "notifications", out var restored) && restored is not null)
        {
            // Interactive render: reuse the SSR data — no extra service call.
            _notifications = restored;
        }
        else
        {
            // SSR: load from the service once.
            _notifications = NotificationService.GetAll();
        }

        if (_notifications.Count > 0)
        {
            _latestTimestamp = _notifications.Max(n => n.Timestamp);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // OnAfterRender only fires in interactive mode, never during SSR.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }

        await Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newer = NotificationService.GetSince(_latestTimestamp);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _latestTimestamp = newer.Max(n => n.Timestamp);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        _persistSub.Dispose();

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

